493	impl Reader<'_> {
494	    /// Read metadata (title and page count) without loading the entire document.
495	    /// This is much faster for large PDFs when you only need basic information.
496	    ///
497	    /// For encrypted PDFs, use `Document::load_metadata_with_password()` instead.
498	    pub fn read_metadata(mut self) -> Result<PdfMetadata> {
499	        let offset = self.buffer.windows(5).position(|w| w == b"%PDF-").unwrap_or(0);
500	        self.buffer = &self.buffer[offset..];
501	
502	        let version =
503	            parser::header(ParserInput::new_extra(self.buffer, "header")).ok_or(ParseError::InvalidFileHeader)?;
504	
505	        let xref_start = Self::get_xref_start(self.buffer)?;
506	        if xref_start > self.buffer.len() {
507	            return Err(Error::Xref(XrefError::Start));
508	        }
509	
510	        let (mut xref, mut trailer) =
511	            parser::xref_and_trailer(ParserInput::new_extra(&self.buffer[xref_start..], "xref"), &self)?;
512	
513	        let mut already_seen = HashSet::new();
514	        let mut prev_xref_start = trailer.remove(b"Prev");
515	        while let Some(prev) = prev_xref_start.and_then(|offset| offset.as_i64().ok()) {
516	            if already_seen.contains(&prev) {
517	                break;
518	            }
519	            already_seen.insert(prev);
520	            if prev < 0 || prev as usize > self.buffer.len() {
521	                return Err(Error::Xref(XrefError::PrevStart));
522	            }
523	
524	            let (prev_xref, prev_trailer) =
525	                parser::xref_and_trailer(ParserInput::new_extra(&self.buffer[prev as usize..], ""), &self)?;
526	            xref.merge(prev_xref);
527	
528	            let prev_xref_stream_start = trailer.remove(b"XRefStm");
529	            if let Some(prev) = prev_xref_stream_start.and_then(|offset| offset.as_i64().ok()) {
530	                if prev < 0 || prev as usize > self.buffer.len() {
531	                    return Err(Error::Xref(XrefError::StreamStart));
532	                }
533	
534	                let (prev_xref, _) =
535	                    parser::xref_and_trailer(ParserInput::new_extra(&self.buffer[prev as usize..], ""), &self)?;
536	                xref.merge(prev_xref);
537	            }
538	
539	            prev_xref_start = prev_trailer.get(b"Prev").cloned().ok();

